// =============================================================================
// CONTACT FORM
// No backend key is wired in, so "Send Message" hands off to the visitor's
// own email client with the fields pre-filled — that's a real send, it just
// goes through their mail app rather than a hidden API call. Swap the
// onSubmit body for an EmailJS/Web3Forms call once you have an API key.
// =============================================================================
function ContactForm({ email }) {
  const [form, setForm] = useState({ name: "", email: "", message: "" });
  const [sent, setSent] = useState(false);

  const update = (field) => (e) => setForm((f) => ({ ...f, [field]: e.target.value }));

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!form.name || !form.email || !form.message) return;
    const subject = encodeURIComponent(`Portfolio contact from ${form.name}`);
    const body = encodeURIComponent(`${form.message}\n\n— ${form.name} (${form.email})`);
    window.location.href = `mailto:${email}?subject=${subject}&body=${body}`;
    setSent(true);
    setTimeout(() => setSent(false), 4000);
  };

  return (
    <form className="contact-form" onSubmit={handleSubmit}>
      <input type="text" placeholder="Your name" value={form.name} onChange={update("name")} required />
      <input type="email" placeholder="Your email" value={form.email} onChange={update("email")} required />
      <textarea placeholder="Your message" rows={4} value={form.message} onChange={update("message")} required />
      <button type="submit" className="btn btn-primary full-width">
        {sent ? "Opening your email app…" : "Send Message"} <ArrowUpRight size={15} />
      </button>
    </form>
  );
}

// Reliable in-page scrolling — used instead of bare href="#id" anchors,
// which can silently no-op inside some embedded/sandboxed page contexts.
function scrollToId(id) {
  return (e) => {
    e.preventDefault();
    const el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: "smooth", block: "start" });
  };
}

